import React, { useMemo, type JSX } from "react";
import IndicatorLineChart from "./IndicatorLineChart";
import { parseHeightPx } from "./klineUtil";
import {
  getJellyAnchorIndex,
  getJellyLiquidationComparisonWindow,
} from "../../../offline/mock_data/jellyevent";
import { JELLY_MORP_LIQUIDATION_SUMMARY } from "../../../offline/mock_data/jellyevent";
import { useOptionalJellyMode } from "../../context/JellyModeContext";

export interface JellyLiquidationComparisonWidgetProps {
  height?: string;
  className?: string;
}

function JellyLiquidationComparisonWidget({
  height,
  className = "",
}: JellyLiquidationComparisonWidgetProps): JSX.Element {
  const jellyCtx = useOptionalJellyMode();
  const frameIndex = jellyCtx?.frameIndex ?? getJellyAnchorIndex();
  const replayPhase = jellyCtx?.replayPhase ?? "intro";

  const points = useMemo(
    () => getJellyLiquidationComparisonWindow(frameIndex, replayPhase),
    [frameIndex, replayPhase],
  );

  const latest = points.at(-1);

  const series = useMemo(
    () => [
      {
        id: "liq-hl",
        label: "HL liquidations",
        data: points.map((p) => ({ time: p.time, value: p.liqCountHL })),
        color: "#ef5350",
        priceScaleId: "left",
      },
      {
        id: "liq-morp",
        label: "Morp liquidations",
        data: points.map((p) => ({ time: p.time, value: p.liqCountMorp })),
        color: "#26a69a",
        priceScaleId: "left",
      },
    ],
    [points],
  );

  const statusText = latest
    ? `HL on-chain liq: ${latest.liqCountHL} · Morp MC est (${JELLY_MORP_LIQUIDATION_SUMMARY.nPositions} pos): ${latest.liqCountMorp}`
    : "Liquidation counts";

  return (
    <div
      className={`jelly-comparison-chart-widget ${className}`.trim()}
      style={{
        width: "100%",
        height: "100%",
        minHeight: parseHeightPx(height),
        display: "flex",
        flexDirection: "column",
      }}
    >
      <div
        style={{
          position: "absolute",
          zIndex: 9,
          bottom:"25px",
          padding: "0.25rem 0.5rem 0",
          fontSize: "0.65rem",
          color: "rgba(255,255,255,0.55)",
        }}
      >
        {statusText}
      </div>
      <IndicatorLineChart
        title="Liquidations · HL on-chain vs Morpheum buckets"
        series={series}
        leftAxisLabel="Cumulative count"
        height={parseHeightPx(height) ?? 220}
        legend={[
          { label: "Hyperliquid", color: "#ef5350" },
          { label: "Morpheum", color: "#26a69a" },
        ]}
      />
    </div>
  );
}

export default JellyLiquidationComparisonWidget;
